SELECT SUM(wickets) AS total_wickets
FROM bowling_performances
WHERE player_id = 1;

SELECT attendance
FROM match_statistics
WHERE match_id = 0;

SELECT AVG(strike_rate) AS avg_strike_rate
FROM (
    SELECT player_id, SUM(runs_scored) / SUM(balls_played) AS strike_rate
    FROM batting_performances
    GROUP BY player_id
) AS player_strike_rates;

SELECT nationality
FROM umpires
WHERE experience_years > 5;

SELECT umpire_id, match_id 
FROM umpires_in_matches 
WHERE role_in_match = 'on-field';

SELECT m.match_id, m.match_date, ms.highest_individual_score
FROM matches m
JOIN match_statistics ms ON m.match_id = ms.match_id;
